import React from 'react';
import ProductoForm from './ProductoForm';
import ProductoTabla from './ProductoTabla';

function App() {
  return (
    <div className="App">
      <h1>Sistema de Inventario</h1>
      <ProductoForm />
      <hr />
      <ProductoTabla />
    </div>
  );
}

export default App;
